package org.eclipse.rdf4j.query.algebra.equivalence;

import static org.junit.jupiter.api.Assertions.assertEquals;
import static org.junit.jupiter.api.Assertions.assertFalse;
import static org.junit.jupiter.api.Assertions.assertNotEquals;
import static org.junit.jupiter.api.Assertions.assertTrue;

import java.util.List;
import java.util.Set;

import org.eclipse.rdf4j.model.IRI;
import org.eclipse.rdf4j.model.TripleTerm;
import org.eclipse.rdf4j.model.ValueFactory;
import org.eclipse.rdf4j.model.impl.SimpleValueFactory;
import org.eclipse.rdf4j.query.algebra.BindingSetAssignment;
import org.eclipse.rdf4j.query.algebra.Bound;
import org.eclipse.rdf4j.query.algebra.Filter;
import org.eclipse.rdf4j.query.algebra.Join;
import org.eclipse.rdf4j.query.algebra.SingletonSet;
import org.eclipse.rdf4j.query.algebra.StatementPattern;
import org.eclipse.rdf4j.query.algebra.TupleExpr;
import org.eclipse.rdf4j.query.algebra.Var;
import org.eclipse.rdf4j.query.impl.MapBindingSet;
import org.junit.jupiter.api.Test;

class SemanticApiTest {
	private static final ValueFactory VF = SimpleValueFactory.getInstance();
	private static final IRI P1 = VF.createIRI("urn:test:p1");
	private static final IRI P2 = VF.createIRI("urn:test:p2");

	@Test
	void semanticSummaryFindsRdf12ValuesInsideValuesRows() {
		TripleTerm triple = VF.createTripleTerm(VF.createIRI("urn:test:s"), P1, VF.createLiteral("o"));
		MapBindingSet row = new MapBindingSet();
		row.setBinding("triple", triple);
		BindingSetAssignment assignment = new BindingSetAssignment();
		assignment.setBindingSets(List.of(row));

		SemanticSummary summary = new SemanticAnalyzer().analyze(assignment);

		assertTrue(summary.usesSparql12Features());
		assertEquals(Set.of("triple"), summary.mayBind());
		assertEquals(Set.of("triple"), summary.mustBind());
	}

	@Test
	void semanticSummaryReportsOnlyUnsatisfiedIncomingReads() {
		StatementPattern input = pattern(P1, "x");
		TupleExpr expression = new Filter(input, new Bound(Var.of("outside")));

		SemanticSummary summary = new SemanticAnalyzer().analyze(expression);

		assertEquals(Set.of("outside"), summary.readsIncomingBindings());
	}

	@Test
	void semanticFingerprintsMatchCheckedJoinNormalForms() {
		TupleExpr a = pattern(P1, "x");
		TupleExpr b = pattern(P2, "y");
		SemanticFingerprinter fingerprinter = new SemanticFingerprinter();

		SemanticFingerprint left = fingerprinter.fingerprint(new Join(a.clone(), b.clone()));
		SemanticFingerprint right = fingerprinter.fingerprint(new Join(b.clone(), a.clone()));

		assertEquals(left, right);
		assertTrue(left.sameCanonicalForm(right));
		assertFalse(left.canonicalEncoding().isEmpty());
	}

	@Test
	void fingerprintIndexChecksExactIdentityInsideDigestBuckets() {
		SemanticSummary summary = new SemanticAnalyzer().analyze(new SingletonSet());
		SemanticFingerprint first = new SemanticFingerprint(
				"sha256:forced-collision",
				"first encoding",
				"first identity",
				ObservationMode.BAG,
				summary);
		SemanticFingerprint second = new SemanticFingerprint(
				"sha256:forced-collision",
				"second encoding",
				"second identity",
				ObservationMode.BAG,
				summary);
		SemanticFingerprintIndex<String> index = new SemanticFingerprintIndex<>();
		index.put(first, "first");
		index.put(second, "second");

		assertNotEquals(first, second);
		assertEquals(List.of("first"), index.findEquivalent(first));
		assertEquals(List.of("second"), index.findEquivalent(second));
		assertEquals(2, index.size());
	}

	private static StatementPattern pattern(IRI predicate, String objectName) {
		return new StatementPattern(
				Var.of("s"),
				Var.of("const-" + predicate.stringValue(), predicate),
				Var.of(objectName));
	}
}
